import{_ as o,o as a,c as r,ak as n}from"./chunks/framework.xMnnZPAZ.js";const b=JSON.parse('{"title":"PerformanceConfiguration","description":"","frontmatter":{},"headers":[],"relativePath":"api/reference/royalapps-community-rdp-winforms-configuration-performance-performanceconfiguration.md","filePath":"api/reference/royalapps-community-rdp-winforms-configuration-performance-performanceconfiguration.md"}'),i={name:"api/reference/royalapps-community-rdp-winforms-configuration-performance-performanceconfiguration.md"};function t(c,e,l,d,s,p){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="performanceconfiguration" tabindex="-1"><code>PerformanceConfiguration</code> <a class="header-anchor" href="#performanceconfiguration" aria-label="Permalink to “PerformanceConfiguration”">​</a></h1><p>Performance related configuration and settings.</p><h2 id="type" tabindex="-1">Type <a class="header-anchor" href="#type" aria-label="Permalink to “Type”">​</a></h2><div class="language-csharp"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">RoyalApps.Community.Rdp.WinForms.Configuration.Performance.PerformanceConfiguration</span></span></code></pre></div><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to “Properties”">​</a></h2><h3 id="bandwidthdetection-bool-↗" tabindex="-1"><code>BandwidthDetection</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings8-bandwidthdetection" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#bandwidthdetection-bool-↗" aria-label="Permalink to “BandwidthDetection (bool) ↗”">​</a></h3><p>Specifies whether bandwidth changes are detected automatically.</p><h3 id="bitmapcaching-bool-↗" tabindex="-1"><code>BitmapCaching</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-bitmappersistence" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#bitmapcaching-bool-↗" aria-label="Permalink to “BitmapCaching (bool) ↗”">​</a></h3><p>Specifies whether bitmap caching is enabled. Persistent caching can improve performance but requires additional disk space.</p><h3 id="clientprotocolspec-clientprotocolspec" tabindex="-1"><code>ClientProtocolSpec</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-connection-clientprotocolspec">ClientProtocolSpec</a>) <a class="header-anchor" href="#clientprotocolspec-clientprotocolspec" aria-label="Permalink to “ClientProtocolSpec (ClientProtocolSpec)”">​</a></h3><p>Specifies the remote desktop protocol used between the client and the server.</p><h3 id="disablecursorsettings-bool" tabindex="-1"><code>DisableCursorSettings</code> (<code>bool</code>) <a class="header-anchor" href="#disablecursorsettings-bool" aria-label="Permalink to “DisableCursorSettings (bool)”">​</a></h3><p>When <code>true</code>, cursor blinking is disabled.</p><h3 id="disablecursorshadow-bool" tabindex="-1"><code>DisableCursorShadow</code> (<code>bool</code>) <a class="header-anchor" href="#disablecursorshadow-bool" aria-label="Permalink to “DisableCursorShadow (bool)”">​</a></h3><p>When <code>true</code>, cursor shadows are disabled.</p><h3 id="disablefullwindowdrag-bool" tabindex="-1"><code>DisableFullWindowDrag</code> (<code>bool</code>) <a class="header-anchor" href="#disablefullwindowdrag-bool" aria-label="Permalink to “DisableFullWindowDrag (bool)”">​</a></h3><p>When <code>true</code>, moving a window only shows its border during the drag operation.</p><h3 id="disablemenuanimations-bool" tabindex="-1"><code>DisableMenuAnimations</code> (<code>bool</code>) <a class="header-anchor" href="#disablemenuanimations-bool" aria-label="Permalink to “DisableMenuAnimations (bool)”">​</a></h3><p>When <code>true</code>, menu animations are disabled.</p><h3 id="disabletheming-bool" tabindex="-1"><code>DisableTheming</code> (<code>bool</code>) <a class="header-anchor" href="#disabletheming-bool" aria-label="Permalink to “DisableTheming (bool)”">​</a></h3><p>When <code>true</code>, theming is disabled in the remote session.</p><h3 id="disablewallpaper-bool" tabindex="-1"><code>DisableWallpaper</code> (<code>bool</code>) <a class="header-anchor" href="#disablewallpaper-bool" aria-label="Permalink to “DisableWallpaper (bool)”">​</a></h3><p>When <code>true</code>, desktop wallpaper is disabled in the remote session.</p><h3 id="enabledesktopcomposition-bool" tabindex="-1"><code>EnableDesktopComposition</code> (<code>bool</code>) <a class="header-anchor" href="#enabledesktopcomposition-bool" aria-label="Permalink to “EnableDesktopComposition (bool)”">​</a></h3><p>When <code>true</code>, desktop composition is enabled.</p><h3 id="enableenhancedgraphics-bool" tabindex="-1"><code>EnableEnhancedGraphics</code> (<code>bool</code>) <a class="header-anchor" href="#enableenhancedgraphics-bool" aria-label="Permalink to “EnableEnhancedGraphics (bool)”">​</a></h3><p>When <code>true</code>, enhanced graphics is enabled.</p><h3 id="enablefontsmoothing-bool" tabindex="-1"><code>EnableFontSmoothing</code> (<code>bool</code>) <a class="header-anchor" href="#enablefontsmoothing-bool" aria-label="Permalink to “EnableFontSmoothing (bool)”">​</a></h3><p>When <code>true</code>, font smoothing is enabled.</p><h3 id="enablehardwaremode-bool" tabindex="-1"><code>EnableHardwareMode</code> (<code>bool</code>) <a class="header-anchor" href="#enablehardwaremode-bool" aria-label="Permalink to “EnableHardwareMode (bool)”">​</a></h3><p>If set to true, hardware assist with graphics decoding is attempted.</p><h3 id="networkconnectiontype-networkconnectiontype-↗" tabindex="-1"><code>NetworkConnectionType</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-performance-networkconnectiontype">NetworkConnectionType</a>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings7-networkconnectiontype" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#networkconnectiontype-networkconnectiontype-↗" aria-label="Permalink to “NetworkConnectionType (NetworkConnectionType) ↗”">​</a></h3><p>Gets or sets the type of network connection used between the client and server. The network connection type information passed on to the server helps the server tune several parameters based on the network connection type</p><h3 id="redirectdirectx-bool-↗" tabindex="-1"><code>RedirectDirectX</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings7-redirectdirectx" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#redirectdirectx-bool-↗" aria-label="Permalink to “RedirectDirectX (bool) ↗”">​</a></h3><p>Specifies whether or not DirectX is enabled or not.</p><p><a href="./../">Back to API index</a></p>',36)])])}const m=o(i,[["render",t]]);export{b as __pageData,m as default};
